Method.Source:
public void insert()
{
    next insert();

    if (ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
        {
            TaxRegistrationTypeApplicabilityRule rule;

            while select rule
                where rule.TaxRegistrationType == this.RecId
            {
                str descriptiveKeyCollection =
                    strFmt("RegistrationType='%1',CountryRegionId='%2'",
                            this.TaxRegstrationType,
                            rule.CountryRegionId);

                ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();

                contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
                contract.parmPrimaryCollectionName("RegistrationTypes");
                contract.parmoperationType("Insert");

                ETGDMSRevereIntegrationEventClass eventClass =
                    ETGDMSRevereIntegrationEventClass::newFromContract(contract);

                eventClass.send();
            }
        }
    }
}

public void update()
{
    TaxRegistrationType origType = this.orig();

    // STORE OLD VALUE IN CACHE
    if (this.TaxRegstrationType != origType.TaxRegstrationType)
    {
        ETGRegistrationTypeCache::setOldValue(this.RecId, origType.TaxRegstrationType);
    }

    next update();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        TaxRegistrationTypeApplicabilityRule rule;

        while select rule
            where rule.TaxRegistrationType == this.RecId
        {
            str oldRegistrationValue =
                (this.TaxRegstrationType != origType.TaxRegstrationType)
                ? origType.TaxRegstrationType
                : this.TaxRegstrationType;

            str descriptiveKeyCollection =
                strFmt("RegistrationType='%1',CountryRegionId='%2',CountryRegionIdOld='%3',RegistrationTypeOld='%4'",
                    this.TaxRegstrationType,
                    rule.CountryRegionId,
                    rule.CountryRegionId,
                    oldRegistrationValue);

            ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
            contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
            contract.parmPrimaryCollectionName("RegistrationTypes");
            contract.parmoperationType("Update");

            ETGDMSRevereIntegrationEventClass eventClass =
            ETGDMSRevereIntegrationEventClass::newFromContract(contract);

            eventClass.send();
        }
    }
}
